    public Amount UBSgetTaxAmountFromAccountingDistribution()
    {
        AccountingDistribution distribution;
        select firstonly sum(TransactionCurrencyAmount) from distribution where distribution.SourceDocumentHeader == this.SourceDocumentHeader
            && distribution.MonetaryAmount == MonetaryAmount::Tax;

        return distribution.TransactionCurrencyAmount;
    }

    public Amount UBSgetTotalAmountFromAccountingDistribution()
    {
        AccountingDistribution distribution;
        select firstonly sum(TransactionCurrencyAmount) from distribution where distribution.SourceDocumentHeader == this.SourceDocumentHeader
            && distribution.MonetaryAmount == MonetaryAmount::ExtendedPrice;

        return distribution.TransactionCurrencyAmount;
    }

    public Amount UBSgetTotalAmountFromAccountingDistribution_PurchReq()
    {
        AccountingDistribution distribution;
        PurchLine PurchLine;
        VendPackingSlipTrans VendPackingSlipTrans;

        select firstonly sum(TransactionCurrencyAmount) from distribution
            join VendPackingSlipTrans where VendPackingSlipTrans.SourceDocumentLine == distribution.SourceDocumentLine
            join PurchLine where PurchLine.InventTransId == VendPackingSlipTrans.InventTransId

            && distribution.SourceDocumentHeader == this.SourceDocumentHeader
            && PurchLine.PurchReqId != ''
            && distribution.MonetaryAmount == MonetaryAmount::ExtendedPrice;


        return distribution.TransactionCurrencyAmount;
    }

    public VendPackingSlipJour UBSgetPreviousPackingSlip()
    {
        VendPackingSlipJour previousPackingSlipJour;
        VendPackingSlipTrans vendPackingSlipTrans;

        select firstonly previousPackingSlipJour
            order by RecId desc
            join vendPackingSlipTrans where vendPackingSlipTrans.PackingSlipId == previousPackingSlipJour.PackingSlipId
            && VendPackingSlipTrans.Qty != 0
            && previousPackingSlipJour.PurchId == this.PurchId
            && previousPackingSlipJour.RecId < this.RecId
            ;
        return previousPackingSlipJour;
    }

    public int UBSgetPackingSlipNumber()
    {
        VendPackingSlipJour VendPackingSlipJour;
        Map vendPackingSlipJourMapping = new Map(Types::Int64, Types::Integer);
        int counter = 1;

        while select VendPackingSlipJour
            order by RecId asc
            where VendPackingSlipJour.PurchId == this.PurchId
        {
            if(!VendPackingSlipJour.isCanceled())
            {
                vendPackingSlipJourMapping.insert(VendPackingSlipJour.RecId, counter);
                counter++;
            }
        }

        return vendPackingSlipJourMapping.lookup(this.RecId);
    }

    public Amount UBSgetMonthTaxAmount()
    {
        VendPackingSlipJour VendPackingSlipJour;
        Amount monthTaxAmount = 0;
        date monthStartDate = dateStartMth(this.DeliveryDate);
        date monthEndDate = endMth(this.DeliveryDate);

        while select VendPackingSlipJour where VendPackingSlipJour.DeliveryDate >= monthStartDate && VendPackingSlipJour.DeliveryDate <= monthEndDate
            && VendPackingSlipJour.PurchId == this.PurchId
        {
            monthTaxAmount += VendPackingSlipJour.UBSgetTaxAmountFromAccountingDistribution();
        }
        return monthTaxAmount;
    }

