    public Amount UBSgetCumulatedTaxAmount()
    {
        VendPackingSlipJour VendPackingSlipJour;
        Amount taxAmount = 0;
        date monthStartDate = dateStartMth(this.DeliveryDate);
        date monthEndDate = endMth(this.DeliveryDate);

        while select VendPackingSlipJour where VendPackingSlipJour.RecId <= this.RecId && VendPackingSlipJour.PurchId == this.PurchId
        {
            taxAmount += VendPackingSlipJour.UBSgetTaxAmountFromAccountingDistribution();
        }
        return taxAmount;
    }

    public Amount UBSgetCumulatedTotalAmount()
    {
