    public display AmountMST displayTotalAmount()
    {
        AmountMST totalAmount = 0;
        VendPackingSlipTrans vendPackingSlipTrans;

        select sum(ValueMST) from vendPackingSlipTrans
            group by vendPackingSlipTrans.PackingSlipId
            where vendPackingSlipTrans.PackingSlipId == this.PackingSlipId;

        if(vendPackingSlipTrans)
        {
            totalAmount = vendPackingSlipTrans.ValueMST;
        }

        return totalAmount;
    }

    public display NoYes displayIsCanceled()
    {
        NoYes isCanceled = NoYes::No;
        VendPackingSlipTrans vendPackingSlipTrans;

        select sum(Qty) from vendPackingSlipTrans
            group by vendPackingSlipTrans.PackingSlipId
            where vendPackingSlipTrans.PackingSlipId == this.PackingSlipId;

        if(vendPackingSlipTrans && vendPackingSlipTrans.Qty == 0)
        {
            isCanceled = NoYes::Yes;
        }

        return isCanceled;
    }
